import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { authAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalStudents: 0,
    totalFaculty: 0,
    totalCourses: 0,
    totalDepartments: 0,
    activeStudents: 0,
    recentEnrollments: 0,
    totalRevenue: 0,
    pendingFees: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const handleAddStudent = () => {
    console.log('Add Student clicked');
    navigate('/students');
  };

  const handleAddFaculty = () => {
    console.log('Add Faculty clicked');
    navigate('/faculty');
  };

  const handleCreateCourse = () => {
    console.log('Create Course clicked');
    navigate('/courses');
  };

  // Fetch real dashboard data from backend
  useEffect(() => {
    const fetchDashboardStats = async () => {
      // Check authentication before making API call
      const token = localStorage.getItem('token');
      const userStr = localStorage.getItem('user');

      if (!token || !userStr) {
        console.log('Dashboard - No authentication found, redirecting to login');
        setError('Please login to access dashboard');
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        setError(null);

        // Debug authentication state before API call
        const token = localStorage.getItem('token');
        const userStr = localStorage.getItem('user');
        console.log('Dashboard - Before API call:');
        console.log('  - Token exists:', !!token);
        console.log('  - User exists:', !!userStr);
        console.log('  - Token value:', token ? token.substring(0, 20) + '...' : 'none');

        const response = await authAPI.getDashboardStats();
        console.log('Dashboard stats response:', response.data);

        setStats(response.data);
      } catch (err) {
        console.error('Error fetching dashboard stats:', err);
        console.error('Error details:', err.response?.status, err.response?.data);
        setError('Failed to load dashboard statistics');
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardStats();
  }, []);

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0
    }).format(amount);
  };

  const StatCard = ({ title, value, change, icon, color = 'blue' }) => (
    <div className="bg-white p-6 rounded-lg shadow hover:shadow-lg transition-shadow duration-200">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-gray-600">{title}</p>
          <p className="text-2xl font-bold text-gray-900 mt-2">{value}</p>
          {change && (
            <p className={`text-sm mt-1 ${change >= 0 ? 'text-green-600' : 'text-red-600'}`}>
              {change >= 0 ? '+' : ''}{change}% from last month
            </p>
          )}
        </div>
        <div className={`p-3 rounded-full ${color === 'blue' ? 'bg-blue-100' : color === 'green' ? 'bg-green-100' : color === 'orange' ? 'bg-orange-100' : 'bg-purple-100'}`}>
          {icon}
        </div>
      </div>
    </div>
  );

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
          <p className="mt-4 text-gray-600">Loading dashboard statistics...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h3 className="text-xl font-bold text-red-600 mb-2">Error Loading Dashboard</h3>
          <p className="text-gray-600">{error}</p>
          <button 
            onClick={() => window.location.reload()}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900 mb-2">
          Welcome back, {user?.firstName || 'Admin'}! 👋
        </h1>
        <p className="text-gray-600">Here's what's happening at your college today</p>
      </div>

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Total Students"
          value={stats.totalStudents.toLocaleString()}
          change={12}
          icon="👥‍🎓"
          color="blue"
        />
        <StatCard
          title="Total Faculty"
          value={stats.totalFaculty.toLocaleString()}
          change={5}
          icon="👨‍🏫"
          color="green"
        />
        <StatCard
          title="Active Courses"
          value={stats.totalCourses.toLocaleString()}
          change={8}
          icon="📚"
          color="purple"
        />
        <StatCard
          title="Departments"
          value={stats.totalDepartments.toLocaleString()}
          change={0}
          icon="🏢"
          color="orange"
        />
      </div>

      {/* Charts and Detailed Stats */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Enrollment Chart */}
        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Student Enrollment Trends</h3>
          <div className="space-y-2">
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">January</span>
              <div className="flex-1 bg-gray-200 rounded-full h-2 ml-3">
                <div className="bg-blue-600 h-2 rounded-full" style={{width: '75%'}}></div>
              </div>
              <span className="text-sm font-medium">{stats.totalStudents - 200}</span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">February</span>
              <div className="flex-1 bg-gray-200 rounded-full h-2 ml-3">
                <div className="bg-blue-600 h-2 rounded-full" style={{width: '82%'}}></div>
              </div>
              <span className="text-sm font-medium">{stats.totalStudents - 100}</span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">March</span>
              <div className="flex-1 bg-gray-200 rounded-full h-2 ml-3">
                <div className="bg-blue-600 h-2 rounded-full" style={{width: '95%'}}></div>
              </div>
              <span className="text-sm font-medium">{stats.totalStudents}</span>
            </div>
          </div>
          <div className="mt-4 pt-4 border-t">
            <div className="flex justify-between text-sm text-gray-600">
              <span>Recent Enrollments</span>
              <span className="font-semibold text-blue-600">{stats.recentEnrollments} this month</span>
            </div>
          </div>
        </div>

        {/* Financial Overview */}
        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Financial Overview</h3>
          <div className="space-y-4">
            <div className="flex justify-between items-center p-3 bg-green-50 rounded">
              <span className="text-sm text-gray-600">Total Revenue</span>
              <span className="text-lg font-bold text-green-600">{formatCurrency(stats.totalRevenue)}</span>
            </div>
            <div className="flex justify-between items-center p-3 bg-orange-50 rounded">
              <span className="text-sm text-gray-600">Pending Fees</span>
              <span className="text-lg font-bold text-orange-600">{stats.pendingFees} students</span>
            </div>
            <div className="flex justify-between items-center p-3 bg-blue-50 rounded">
              <span className="text-sm text-gray-600">Collected This Month</span>
              <span className="text-lg font-bold text-blue-600">{formatCurrency(stats.totalRevenue * 0.4)}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="mt-8">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Quick Actions</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <button 
            onClick={handleAddStudent}
            className="p-4 bg-white border border-gray-200 rounded-lg hover:border-blue-500 hover:bg-blue-50 transition-all duration-200 hover:shadow-lg"
            title="Add New Student"
          >
            <div className="text-blue-600 text-2xl mb-2">➕</div>
            <p className="font-medium text-gray-900">Add Student</p>
            <p className="text-sm text-gray-600">Enroll new students</p>
          </button>
          <button 
            onClick={handleAddFaculty}
            className="p-4 bg-white border border-gray-200 rounded-lg hover:border-green-500 hover:bg-green-50 transition-all duration-200 hover:shadow-lg"
            title="Add New Faculty"
          >
            <div className="text-green-600 text-2xl mb-2">👨‍🏫</div>
            <p className="font-medium text-gray-900">Add Faculty</p>
            <p className="text-sm text-gray-600">Hire new faculty</p>
          </button>
          <button 
            onClick={handleCreateCourse}
            className="p-4 bg-white border border-gray-200 rounded-lg hover:border-purple-500 hover:bg-purple-50 transition-all duration-200 hover:shadow-lg"
            title="Create New Course"
          >
            <div className="text-purple-600 text-2xl mb-2">📚</div>
            <p className="font-medium text-gray-900">Create Course</p>
            <p className="text-sm text-gray-600">Add new courses</p>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
